403		port_selftriglo			<= CcSFromAxOut(CcSFromAxi_SelfTrigLo_Rng);
404		port_selftrighi			<= CcSFromAxOut(CcSFromAxi_SelfTrigHi_Rng);
405		port_selftrigchena		<= CcSFromAxOut(CcSFromAxi_SelfTrigChEna_Rng);
406		port_selftrigonexit		<= CcSFromAxOut(CcSFromAxi_SelfTrigOnExit_c);
407		port_selftrigonenter	<= CcSFromAxOut(CcSFromAxi_SelfTrigOnEnter_c);
408		port_trigena			<= CcSFromAxOut(CcSFromAxi_TrigEna_Rng);
409		port_swtrig				<= CcSFromAxOut(CcSFromAxi_SwTrig_c);
410		port_minrecperiod		<= CcSFromAxOut(CcSFromAxi_MinRecPeriod_Rng);
411		port_enableexttrig		<= CcSFromAxOut(CcSFromAxi_EnableExtTrig_Rng);
412		
413		-- *** Pulses from AXI to Data domain ***
414		CcPFromAxIn(CcPFromAxi_Arm_c)			<= reg_cfg_arm;
415		CcPFromAxIn(CcPFromAxi_Ack_c)			<= AckDone;
416		CcPFromAxIn(CcPFromAxi_TrigCntClr_c)	<= reg_cfg_trigcntclr;
417		
418		i_cc_pulse_fromAxi : entity work.psi_common_pulse_cc
419			generic map (
420				num_pulses_g	=> CcFromAxi_Width_c
421			)
422			port map (
423				a_clk_i 		=> s00_axi_aclk,
424				a_rst_i		=> AxiRst,
425				a_rst_o		=> open,
426				a_dat_i		=> CcPFromAxIn,
427				b_clk_i		=> Clk,
428				b_rst_i		=> Rst,
429				b_rst_o		=> open,
430				b_dat_o		=> CcPFromAxOut
431			);
432			
433		port_cfg_arm 		<= CcPFromAxOut(CcPFromAxi_Arm_c);
434		port_cfg_ack 		<= CcPFromAxOut(CcPFromAxi_Ack_c);
435		port_cfg_trigcntclr	<= CcPFromAxOut(CcPFromAxi_TrigCntClr_c);
436		
437		-- *** Pulses from Data to Axi domain ***
438		CcPToAxIn(CsPToAxi_Done_c)			<= port_done;
439		
440		i_cc_pulse_toAxi : entity work.psi_common_pulse_cc
441			generic map (
442				num_pulses_g	=> CsPToAxi_Width_c
443			)
444			port map (
445				a_clk_i 		=> Clk,
446				a_rst_i		=> Rst,
447				a_rst_o		=> open,
448				a_dat_i		=> CcPToAxIn,
449				b_clk_i		=> s00_axi_aclk,
450				b_rst_i		=> AxiRst,
451				b_rst_o		=> open,
452				b_dat_o		=> CcPToAxOut
453			);
454			
455		Done_Irq 		<= CcPToAxOut(CsPToAxi_Done_c);
456	
457		------------------------------------------
458		-- instantiate User Logic
459		------------------------------------------
460		i_data_rec : entity work.data_rec
461			generic map (
462				NumOfInputs_g	=> NumOfInputs_g,
463				InputWidth_g	=> InputWidth_g,
464				MemoryDepth_g	=> MemoryDepth_g,
465				TrigInputs_g	=> TrigInputs_g
466			)
467			port map
468			(
469				-- Control Signals
470				Clk				=> Clk,
471				Rst				=> RstProc,
472				-- Data Ports
473				In_Data0		=> In_Data0,			
474				In_Data1		=> In_Data1,			
475				In_Data2		=> In_Data2,			
476				In_Data3		=> In_Data3,			
477				In_Data4		=> In_Data4,			
478				In_Data5		=> In_Data5,			
479				In_Data6		=> In_Data6,			
480				In_Data7		=> In_Data7,			
481				In_Vld			=> In_Vld,		
482				-- Trigger Ports
483				Trig_In			=> Trig_In,
484				Trig_Out		=> Trig_Out,
485				-- Register Ports
486				State			=> port_stat_state,
487				Arm				=> port_cfg_arm,
488				Ack				=> port_cfg_ack,
489				PreTrigSpls		=> port_pretrig,
490				TotalSpls		=> port_totspl,			
491				SelfTrigLo		=> port_selftriglo,
492				SelfTrigHi		=> port_selftrighi,
493				SelfTrigChEna	=> port_selftrigchena,
494				SelfTrigOnExit	=> port_selftrigonexit,
495				SelfTrigOnEnter	=> port_selftrigonenter,
496				SwTrig			=> port_swtrig,
497				Done			=> port_done,
498				TrigCntClr		=> port_cfg_trigcntclr,
499				TrigCnt			=> port_trigcnt,
500				DoneTime		=> port_donetime,
501				TrigEna			=> port_trigena,
502				EnableExtTrig	=> port_enableexttrig,
503				MinRecPeriod	=> port_minrecperiod,
504				-- Memory Ports
505				Mem_Wr			=> RecMemWr,
506				Mem_Adr			=> RecMemAdr,
507				Mem_Data		=> RecMemData,
508				FirstSplAddr	=> FirstSplAddr
509			);
510			
511		-- For power of 2 memory depth, the address logic is relatively simple
512		g_pwr2mem : if not NonPwr2MemDepth_c generate
513			AxiMemAdr		<= std_logic_vector(unsigned(mem_addr(log2ceil(MemoryDepth_g)+1 downto 2)) + unsigned(FirstSplAddr));
514		end generate;
515		
516		-- For non power of 2 memory depth, the address logic is more complex and prone to slow timing, therefore it is only implemented if required
517		g_npwr2mem : if NonPwr2MemDepth_c generate
518			signal AxiMemAddrUnwrapped 	: std_logic_vector(AxiMemAdr'high+1 downto 0);
519			signal MemAddrFull			: std_logic_vector(AxiMemAddrUnwrapped'range);
520		begin
521			AxiMemAddrUnwrapped		<= std_logic_vector(unsigned(mem_addr(log2ceil(MemoryDepth_g)+1 downto 2)) + unsigned('0' & FirstSplAddr));
522			MemAddrFull				<= AxiMemAddrUnwrapped when unsigned(AxiMemAddrUnwrapped) < MemoryDepth_g else 
523									   std_logic_vector(unsigned(AxiMemAddrUnwrapped) - MemoryDepth_g);
524			AxiMemAdr				<= MemAddrFull(AxiMemAdr'range);
525		end generate;
526			
527		
528		mem_read_mux : process(s00_axi_aclk)
529		begin
530			if rising_edge(s00_axi_aclk) then
531				AxiMemSel		<= mem_addr(log2ceil(MemoryDepth_g)+4 downto log2ceil(MemoryDepth_g)+2);
532			end if;
533		end process;
534		mem_rdata(31 downto InputWidth_g)	<= 	(others => mem_rdata(InputWidth_g-1)); --sign extension
535		mem_rdata(InputWidth_g-1 downto 0) 	<= 	AxiMemOut(0) when unsigned(AxiMemSel) = 0 else
536												AxiMemOut(1) when unsigned(AxiMemSel) = 1 else
537												AxiMemOut(2) when unsigned(AxiMemSel) = 2 else
538												AxiMemOut(3) when unsigned(AxiMemSel) = 3 else
539												AxiMemOut(4) when unsigned(AxiMemSel) = 4 else
540												AxiMemOut(5) when unsigned(AxiMemSel) = 5 else
541												AxiMemOut(6) when unsigned(AxiMemSel) = 6 else
542												AxiMemOut(7);
543		
544		
545		g_mem : for i in 0 to NumOfInputs_g-1 generate
546		begin	
547			i_mem : entity work.psi_common_tdp_ram
548				generic map (
549					depth_g		=> MemoryDepth_g,
550					width_g		=> InputWidth_g,
551					behavior_g	=> "RBW"
552				)
553				port map (
554					-- Port A
555					a_clk_i		=> Clk,
556					a_addr_i		=> RecMemAdr,
557					a_wr_i			=> RecMemWr,
558					a_dat_i		=> RecMemData((i+1)*InputWidth_g-1 downto i*InputWidth_g),
559					a_dat_o		=> open,
560					
561					-- Port B
562					b_clk_i		=> s00_axi_aclk,
563					b_addr_i		=> AxiMemAdr,
564					b_wr_i			=> '0',
565					b_dat_i		=> (others => '0'),
566					b_dat_o		=> AxiMemOut(i)
567				);
568		end generate;
569	  
570	end rtl;
571

