5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Libraries
9	------------------------------------------------------------------------------
10	library ieee;
11		use ieee.std_logic_1164.all;
12		use ieee.numeric_std.all;
13		
14	library std;
15		use std.textio.all;
16	
17	library work;
18		use work.psi_tb_txt_util.all;
19		use work.psi_tb_axi_pkg.all;
20		use work.top_tb_pkg.all;
21		use work.top_tb_case0_pkg.all;
22		use work.top_tb_case1_pkg.all;
23		use work.top_tb_case2_pkg.all;
24		use work.top_tb_case3_pkg.all;
25		use work.top_tb_case4_pkg.all;
26	
27	entity top_tb is
28		generic (
29			MemoryDepth_g				: positive					:= 32
30		);
31	end entity top_tb;
32	
33	architecture sim of top_tb is
34	
35		-------------------------------------------------------------------------
36		-- AXI Definition
37		-------------------------------------------------------------------------
38		constant ID_WIDTH 		: integer 	:= 1;
39		constant ADDR_WIDTH 	: integer	:= 14;
40		constant USER_WIDTH		: integer	:= 1;
41		constant DATA_WIDTH		: integer	:= 32;
42		constant BYTE_WIDTH		: integer	:= DATA_WIDTH/8;
43		constant TRIG_FWD 		: boolean 	:= true;
44		
45		subtype ID_RANGE is natural range ID_WIDTH-1 downto 0;
46		subtype ADDR_RANGE is natural range ADDR_WIDTH-1 downto 0;
47		subtype USER_RANGE is natural range USER_WIDTH-1 downto 0;
48		subtype DATA_RANGE is natural range DATA_WIDTH-1 downto 0;
49		subtype BYTE_RANGE is natural range BYTE_WIDTH-1 downto 0;
50		
51		signal axi_ms : axi_ms_r (	arid(ID_RANGE), awid(ID_RANGE),
52									araddr(ADDR_RANGE), awaddr(ADDR_RANGE),
53									aruser(USER_RANGE), awuser(USER_RANGE), wuser(USER_RANGE),
54									wdata(DATA_RANGE),
55									wstrb(BYTE_RANGE));
56		
57		signal axi_sm : axi_sm_r (	rid(ID_RANGE), bid(ID_RANGE),
58									ruser(USER_RANGE), buser(USER_RANGE),
59									rdata(DATA_RANGE));
60	
61		-------------------------------------------------------------------------
62		-- Constants
63		-------------------------------------------------------------------------	
64		constant OutWidth_c		: integer		:= 32;
65		constant UpdateRate_c	: time			:= (1 sec) / 1000000;
66		
67		-------------------------------------------------------------------------
68		-- TB Defnitions
69		-------------------------------------------------------------------------
70		constant	ClockFrequencyAxi_c	: real		:= 125.0e6;
71		constant	ClockPeriodAxi_c	: time		:= (1 sec)/ClockFrequencyAxi_c;
72		signal 		TbRunning			: boolean 	:= True;
73		signal		TestCase			: integer	:= -1;	
74	
75		
76		-------------------------------------------------------------------------
77		-- Interface Signals
78		-------------------------------------------------------------------------
79		signal aclk			: std_logic							:= '0';
80		signal aresetn		: std_logic							:= '0';
81		signal Clk 			: std_logic							:= '0';
82		signal Rst			: std_logic							:= '1';
83		signal DataDut		: Data_t(7 downto 0)				:= (others => (others => '0'));
84		signal ToDut		: In_t								:= (	In_Data	=> (others => (others => '0')),
85																		In_Vld	=> '0',
86																		Trig_In	=> (others => '0'));
87		signal FromDut		: Out_t;
88	
89	begin
90	
91		g_data : for i in 0 to NumOfInputs_c-1 generate
92			DataDut(i)	<= ToDut.In_Data(i);
93		end generate;
94	
95		-------------------------------------------------------------------------
96		-- DUT
97		-------------------------------------------------------------------------
98		i_dut : entity work.data_rec_vivado_wrp
99			generic map
100			(
101				-- Component Generics
102				InputWidth_g				=> InputWidth_c,
103				NumOfInputs_g				=> NumOfInputs_c,
104				MemoryDepth_g				=> MemoryDepth_g,
105				TrigInputs_g				=> TriggerInputs_c,
106				TrigForwarding_g			=> TRIG_FWD,
107				-- AXI
108				C_S00_AXI_ID_WIDTH     	 	=> ID_WIDTH,
109				C_S00_AXI_ADDR_WIDTH      	=> ADDR_WIDTH
110			)
111			port map
112			(
113				-- Control Signals
114				Clk					=> Clk,
115				Rst					=> Rst,
116				-- Data Input
117				In_Data0			=> DataDut(0),
118				In_Data1			=> DataDut(1),
119				In_Data2			=> DataDut(2),
120				In_Data3			=> DataDut(3),
121				In_Data4			=> DataDut(4),
