61		-------------------------------------------------------------------------	
62		procedure InputSamples(			samples 	: in	integer;
63								signal	inp			: out	In_t;
64								signal 	clk			: in	std_logic;
65										startCnt	: in	integer := -1;
66										trigAt		: in	integer := -1;
67										dutycycle	: in	integer := 1;
68										trigIdx		: in	integer := 0);
69										
70		procedure CheckData(			samples		: in 	integer;
71										startValue	: in 	integer;
72								signal 	ms			: out	axi_ms_r;
73								signal 	sm			: in	axi_sm_r;
74								signal 	aclk		: in	std_logic);
