76		procedure InputSamplesNoCh(		samples 	: in	integer;
77								signal	inp			: out	In_t;
78								signal 	clk			: in	std_logic;
79										startCnt	: in	integer := -1000000;
80										chStep		: in	integer := 1;
81										cntStep		: in	integer := 1);
