94	package body top_tb_pkg is
95		procedure InputSamples(			samples 	: in	integer;
96								signal	inp			: out	In_t;
97								signal 	clk			: in	std_logic;
98										startCnt	: in	integer := -1;
99										trigAt		: in	integer := -1;
100										dutycycle	: in	integer := 1;
101										trigIdx		: in	integer := 0) is
102			variable Data 	: unsigned(InputWidth_c-1 downto 0);
103		begin
104			if startCnt >= 0 then
105				PatternCnt_v := startCnt;
106			end if;
107			wait until rising_edge(Clk);
108			for cnt in 0 to samples-1 loop
109				--Data := to_unsigned(startCnt+cnt, InputWidth_c);
110				Data := to_unsigned(PatternCnt_v, InputWidth_c);
111				PatternCnt_v := PatternCnt_v+1;
112				-- Apply channel offs
113				for d in 0 to NumOfInputs_c-1 loop
114					Data(Data'left downto Data'left-2) := to_unsigned(d, 3);
115					inp.In_Data(d) <= std_logic_vector(Data);
116				end loop;
117				-- Trigger if required
118				if cnt = trigAt then
119					inp.Trig_In(trigIdx) <= '1';
120				end if;
121				for w in 0 to dutycycle-2 loop
122					wait until rising_edge(Clk);
123				end loop;
124				inp.In_Vld <= '1';
125				wait until rising_edge(Clk);
126				inp.In_Vld <= '0';
127				if trigAt /= -1 then -- do only touch trigger it was set by this function
128					inp.Trig_In <= (others => '0');
129				end if;
130			end loop;
131			inp.In_Vld <= '0';
132		end procedure;
133		
134		
135		procedure CheckData(			samples		: in integer;
136										startValue	: in integer;
137								signal 	ms			: out	axi_ms_r;
138								signal 	sm			: in	axi_sm_r;
139								signal 	aclk		: in	std_logic) is
140			variable ExpVal_v 		: integer;
141		begin	
142			for ch in 0 to NumOfInputs_c-1 loop				
143				for spl in 0 to samples-1 loop
144					ExpVal_v := ch*2**(InputWidth_c-3)+spl+startValue;
145					axi_single_expect(MemAddr(ch, spl, MemoryDepth_v), ExpVal_v, ms, sm, aclk, "Data Ch" & integer'image(ch) & " Spl " & integer'image(spl));
146				end loop;
147			end loop; 
148		end procedure;
149		
150		procedure InputSamplesNoCh(		samples 	: in	integer;
151								signal	inp			: out	In_t;
152								signal 	clk			: in	std_logic;
153										startCnt	: in	integer := -1000000;
154										chStep		: in	integer := 1;
155										cntStep		: in	integer := 1) is	
156			variable Data 	: signed(InputWidth_c-1 downto 0);
157			variable ChData	: signed(Data'range);
158		begin
159			if startCnt /= -1000000 then
160				PatternCnt_v := startCnt;
161			end if;
162			wait until rising_edge(Clk);
163			for cnt in 0 to samples-1 loop
164				Data := to_signed(PatternCnt_v, InputWidth_c);
165				PatternCnt_v := PatternCnt_v+cntStep;
166				-- Apply channel offs
167				for d in 0 to NumOfInputs_c-1 loop
168					ChData := Data + chStep*d;
169					inp.In_Data(d) <= std_logic_vector(ChData);
170				end loop;
171				inp.In_Vld <= '1';
172				wait until rising_edge(Clk);
173				inp.In_Vld <= '0';
174				inp.Trig_In <= (others => '0');
175			end loop;
176			inp.In_Vld <= '0';
177		end procedure;	
178	
179		procedure CheckDataNoCh(		samples		: in 	integer;
180										startValue	: in 	integer;
181										chStep		: in	integer := 1;	
182										cntStep		: in	integer := 1;
183								signal 	ms			: out	axi_ms_r;
184								signal 	sm			: in	axi_sm_r;
185								signal 	aclk		: in	std_logic) is	
186			variable ExpVal_v 		: integer;
187		begin	
188			for ch in 0 to NumOfInputs_c-1 loop				
189				for spl in 0 to samples-1 loop
190					ExpVal_v := ch*chStep+spl*cntStep+startValue;
191					axi_single_expect(MemAddr(ch, spl, MemoryDepth_v), ExpVal_v, ms, sm, aclk, "Data Ch" & integer'image(ch) & " Spl " & integer'image(spl));
192				end loop;
193			end loop;
194		end procedure;
195		
196	end top_tb_pkg;
