23	------------------------------------------------------------------------------
24	-- Package Header
25	------------------------------------------------------------------------------
26	package top_tb_case4_pkg is
27	
28		constant CaseName_c : string := "Recovery from illegal configurations";
29	
30		procedure run(	signal ms		: out	axi_ms_r;
31						signal sm		: in	axi_sm_r;
32						signal aclk		: in	std_logic;
33						signal Clk 		: in 	std_logic;
34						signal ToDut	: out	In_t;
35						signal FromDut	: in	Out_t);
36						
37	end top_tb_case4_pkg;
38	
39	------------------------------------------------------------------------------
40	-- Package Body
41	------------------------------------------------------------------------------
42	package body top_tb_case4_pkg is
43	
44		procedure run(	signal ms		: out	axi_ms_r;
45						signal sm		: in	axi_sm_r;
46						signal aclk		: in	std_logic;
47						signal Clk 		: in 	std_logic;
48						signal ToDut	: out	In_t;
49						signal FromDut	: in	Out_t) is
50			variable lastDoneCheck		: time;
51		begin
52			-- Print Message
53			print("Test: " & CaseName_c);
54			lastDoneCheck := now;
55			
56			-- Common Configuration
57			axi_single_write(Reg_TrigEna_Addr_c, 1*2**Reg_TrigEna_ExtIdx_c, ms, sm, aclk);	
58			
59			-- Arm when already armed
60			axi_single_write(Reg_Totspl_Addr_c, 10, ms, sm, aclk);
61			axi_single_write(Reg_Pretrig_Addr_c, 5, ms, sm, aclk);
62			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
63			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
64			wait for 100 ns;
65			InputSamples(MemoryDepth_v*2, ToDut, Clk, 0, MemoryDepth_v);
66			wait for 100 ns;	
67			CheckData(10, MemoryDepth_v-5, ms, sm, aclk);
68			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
69	
70			-- Pre-Trigger > Total
71			axi_single_write(Reg_Totspl_Addr_c, 10, ms, sm, aclk);
72			axi_single_write(Reg_Pretrig_Addr_c, 15, ms, sm, aclk);
73			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
74			wait for 100 ns;
75			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StatePreTrig_c, ms, sm, aclk, "PreTrig Status", 3, 0);	
76			InputSamples(MemoryDepth_v*2, ToDut, Clk, 0, MemoryDepth_v);
77			wait for 100 ns;	
78			-- data is not important but clean recovery is
79			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
80			lastDoneCheck := now;
81			
82			-- check correct behavior after recovery
83			axi_single_write(Reg_Totspl_Addr_c, 10, ms, sm, aclk);
84			axi_single_write(Reg_Pretrig_Addr_c, 5, ms, sm, aclk);
85			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
86			wait for 200 ns;
87			assert FromDut.Done_Irq = '0' and FromDut.Done_Irq'last_event > now - lastDoneCheck report "Done_Irq was high after arming" severity error;
88			lastDoneCheck := now;
89			InputSamples(MemoryDepth_v*2, ToDut, Clk, 100, MemoryDepth_v);
90			wait for 100 ns;	
91			assert FromDut.Done_Irq'last_event < now - lastDoneCheck report "Done_Irq was low after recording" severity error;
92			lastDoneCheck := now;
93			CheckData(10, 100+MemoryDepth_v-5, ms, sm, aclk);
94			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);		
95			
96			-- Total Samples = 0
97			axi_single_write(Reg_Totspl_Addr_c, 0, ms, sm, aclk);
98			axi_single_write(Reg_Pretrig_Addr_c, 15, ms, sm, aclk);
99			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
100			wait for 100 ns;
101			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StatePreTrig_c, ms, sm, aclk, "PreTrig Status", 3, 0);	
102			InputSamples(MemoryDepth_v*2, ToDut, Clk, 0, MemoryDepth_v);
103			wait for 100 ns;	
104			-- data is not important but clean recovery is
105			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
106			lastDoneCheck := now;		
107			
108			-- check correct behavior after recovery
109			axi_single_write(Reg_Totspl_Addr_c, 10, ms, sm, aclk);
110			axi_single_write(Reg_Pretrig_Addr_c, 5, ms, sm, aclk);
111			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
112			wait for 200 ns;
113			assert FromDut.Done_Irq = '0' and FromDut.Done_Irq'last_event > now - lastDoneCheck report "Done_Irq was high after arming" severity error;
114			lastDoneCheck := now;
115			InputSamples(MemoryDepth_v*2, ToDut, Clk, 100, MemoryDepth_v);
116			wait for 100 ns;	
117			assert FromDut.Done_Irq'last_event < now - lastDoneCheck report "Done_Irq was low after recording" severity error;
118			lastDoneCheck := now;
119			CheckData(10, 100+MemoryDepth_v-5, ms, sm, aclk);
120			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);			
121	
122					
123		end procedure;
124		
125		
126	end top_tb_case4_pkg;
